(window.webpackJsonp=window.webpackJsonp||[]).push([[1385],{1654:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">time</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">m</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> minTime = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">time, m</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> sum=time.reduce(<span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">a,b</span>)=&gt;</span>a+b)\\n  <span class=\\"hljs-keyword\\">let</span> r=<span class=\\"hljs-built_in\\">Math</span>.ceil(sum/m),l=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">while</span>(l&lt;r){\\n    <span class=\\"hljs-keyword\\">let</span> aux=<span class=\\"hljs-built_in\\">Array</span>(m).fill(<span class=\\"hljs-number\\">0</span>)\\n    <span class=\\"hljs-keyword\\">let</span> biggest=<span class=\\"hljs-built_in\\">Array</span>(m).fill(-<span class=\\"hljs-literal\\">Infinity</span>)\\n    <span class=\\"hljs-keyword\\">let</span> used=<span class=\\"hljs-built_in\\">Array</span>(m).fill(<span class=\\"hljs-literal\\">false</span>)\\n    <span class=\\"hljs-keyword\\">let</span> idx=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">let</span> mid=<span class=\\"hljs-built_in\\">Math</span>.floor((l+r)/<span class=\\"hljs-number\\">2</span>)\\n    <span class=\\"hljs-keyword\\">let</span> needLess=<span class=\\"hljs-literal\\">true</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;time.length;i++){\\n      <span class=\\"hljs-keyword\\">let</span> n=time[i]\\n      <span class=\\"hljs-comment\\">// console.log(aux,used,n,mid)</span>\\n      <span class=\\"hljs-keyword\\">if</span>(aux[idx]+n&lt;=mid){\\n        aux[idx]+=n\\n        <span class=\\"hljs-keyword\\">if</span>(!used[idx])biggest[idx]=<span class=\\"hljs-built_in\\">Math</span>.max(biggest[idx],n)\\n      }<span class=\\"hljs-keyword\\">else</span>{\\n        <span class=\\"hljs-keyword\\">if</span>(!used[idx]){\\n          biggest[idx]=<span class=\\"hljs-built_in\\">Math</span>.max(biggest[idx],n)\\n          used[idx]=<span class=\\"hljs-literal\\">true</span>\\n          <span class=\\"hljs-keyword\\">if</span>(biggest[idx]===n){\\n            <span class=\\"hljs-keyword\\">continue</span>\\n          }<span class=\\"hljs-keyword\\">else</span>{\\n            aux[idx]-=biggest[idx]\\n            i--\\n          }\\n          \\n        }<span class=\\"hljs-keyword\\">else</span>{\\n          <span class=\\"hljs-keyword\\">if</span>(idx&lt;m<span class=\\"hljs-number\\">-1</span>){\\n            idx++\\n            i--\\n          }<span class=\\"hljs-keyword\\">else</span>{\\n             needLess=<span class=\\"hljs-literal\\">false</span>\\n            <span class=\\"hljs-keyword\\">break</span>\\n          }          \\n        }\\n      }\\n    }\\n    <span class=\\"hljs-comment\\">// console.log(mid,needLess)</span>\\n    <span class=\\"hljs-keyword\\">if</span>(needLess)r=mid\\n    <span class=\\"hljs-keyword\\">else</span> l=mid+<span class=\\"hljs-number\\">1</span>\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> l\\n};\\n</code></pre>\\n"],"titleSlug":"xiao-zhang-shua-ti-ji-hua","hasThinking":false,"content":"<p>\u4e3a\u4e86\u63d0\u9ad8\u81ea\u5df1\u7684\u4ee3\u7801\u80fd\u529b\uff0c\u5c0f\u5f20\u5236\u5b9a\u4e86 <code>LeetCode</code> \u5237\u9898\u8ba1\u5212\uff0c\u4ed6\u9009\u4e2d\u4e86 <code>LeetCode</code> \u9898\u5e93\u4e2d\u7684 <code>n</code> \u9053\u9898\uff0c\u7f16\u53f7\u4ece <code>0</code> \u5230 <code>n-1</code>\uff0c\u5e76\u8ba1\u5212\u5728 <code>m</code> \u5929\u5185<strong>\u6309\u7167\u9898\u76ee\u7f16\u53f7\u987a\u5e8f</strong>\u5237\u5b8c\u6240\u6709\u7684\u9898\u76ee\uff08\u6ce8\u610f\uff0c\u5c0f\u5f20\u4e0d\u80fd\u7528\u591a\u5929\u5b8c\u6210\u540c\u4e00\u9898\uff09\u3002</p>\\n\\n<p>\u5728\u5c0f\u5f20\u5237\u9898\u8ba1\u5212\u4e2d\uff0c\u5c0f\u5f20\u9700\u8981\u7528 <code>time[i]</code> \u7684\u65f6\u95f4\u5b8c\u6210\u7f16\u53f7 <code>i</code> \u7684\u9898\u76ee\u3002\u6b64\u5916\uff0c\u5c0f\u5f20\u8fd8\u53ef\u4ee5\u4f7f\u7528\u573a\u5916\u6c42\u52a9\u529f\u80fd\uff0c\u901a\u8fc7\u8be2\u95ee\u4ed6\u7684\u597d\u670b\u53cb\u5c0f\u6768\u9898\u76ee\u7684\u89e3\u6cd5\uff0c\u53ef\u4ee5\u7701\u53bb\u8be5\u9898\u7684\u505a\u9898\u65f6\u95f4\u3002\u4e3a\u4e86\u9632\u6b62&ldquo;\u5c0f\u5f20\u5237\u9898\u8ba1\u5212&rdquo;\u53d8\u6210&ldquo;\u5c0f\u6768\u5237\u9898\u8ba1\u5212&rdquo;\uff0c\u5c0f\u5f20\u6bcf\u5929\u6700\u591a\u4f7f\u7528\u4e00\u6b21\u6c42\u52a9\u3002</p>\\n\\n<p>\u6211\u4eec\u5b9a\u4e49 <code>m</code> \u5929\u4e2d\u505a\u9898\u65f6\u95f4\u6700\u591a\u7684\u4e00\u5929\u8017\u65f6\u4e3a <code>T</code>\uff08\u5c0f\u6768\u5b8c\u6210\u7684\u9898\u76ee\u4e0d\u8ba1\u5165\u505a\u9898\u603b\u65f6\u95f4\uff09\u3002\u8bf7\u4f60\u5e2e\u5c0f\u5f20\u6c42\u51fa\u6700\u5c0f\u7684 <code>T</code>\u662f\u591a\u5c11\u3002</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<blockquote>\\n<p>\u8f93\u5165\uff1a<code>time = [1,2,3,3], m = 2</code></p>\\n\\n<p>\u8f93\u51fa\uff1a<code>3</code></p>\\n\\n<p>\u89e3\u91ca\uff1a\u7b2c\u4e00\u5929\u5c0f\u5f20\u5b8c\u6210\u524d\u4e09\u9898\uff0c\u5176\u4e2d\u7b2c\u4e09\u9898\u627e\u5c0f\u6768\u5e2e\u5fd9\uff1b\u7b2c\u4e8c\u5929\u5b8c\u6210\u7b2c\u56db\u9898\uff0c\u5e76\u4e14\u627e\u5c0f\u6768\u5e2e\u5fd9\u3002\u8fd9\u6837\u505a\u9898\u65f6\u95f4\u6700\u591a\u7684\u4e00\u5929\u82b1\u8d39\u4e86 3 \u7684\u65f6\u95f4\uff0c\u5e76\u4e14\u8fd9\u4e2a\u503c\u662f\u6700\u5c0f\u7684\u3002</p>\\n</blockquote>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<blockquote>\\n<p>\u8f93\u5165\uff1a<code>time = [999,999,999], m = 4</code></p>\\n\\n<p>\u8f93\u51fa\uff1a<code>0</code></p>\\n\\n<p>\u89e3\u91ca\uff1a\u5728\u524d\u4e09\u5929\u4e2d\uff0c\u5c0f\u5f20\u6bcf\u5929\u6c42\u52a9\u5c0f\u6768\u4e00\u6b21\uff0c\u8fd9\u6837\u4ed6\u53ef\u4ee5\u5728\u4e09\u5929\u5185\u5b8c\u6210\u6240\u6709\u7684\u9898\u76ee\u5e76\u4e0d\u82b1\u4efb\u4f55\u65f6\u95f4\u3002</p>\\n</blockquote>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u9650\u5236\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= time.length &lt;= 10^5</code></li>\\n\\t<li><code>1 &lt;= time[i] &lt;= 10000</code></li>\\n\\t<li><code>1 &lt;= m &lt;= 1000</code></li>\\n</ul>\\n","title":"LCP 12. \u5c0f\u5f20\u5237\u9898\u8ba1\u5212","relatedTags":[],"difficult":"Middle","lang":["javascript"],"uniqueID":"LCP 12"}')}}]);